  if (typeof value === "number") return String(value);
  return `'${String(value).replaceAll("'", "''")}'`;
}

function sqlite(input, json = false) {
  const args = json ? ["-json", dbPath, input] : [dbPath, input];
  const out = execFileSync("sqlite3", args, { encoding: "utf8" }).trim();
  if (!json || !out) return json ? [] : out;
  return JSON.parse(out);
}

function dbRun(statements) {
  sqlite(Array.isArray(statements) ? statements.join(";\n") + ";" : statements);
}

function dbAll(query) {
  return sqlite(query, true);
}

function dbGet(query) {
  return dbAll(query)[0] || null;
}

function lastId(table) {
  return dbGet(`SELECT id FROM ${table} ORDER BY id DESC LIMIT 1`).id;
}

